(window.webpackJsonp=window.webpackJsonp||[]).push([[569],{838:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">requests</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> maxSumRangeQuery = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums, requests</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> MOD=<span class=\\"hljs-number\\">1e9</span>+<span class=\\"hljs-number\\">7</span>\\n    <span class=\\"hljs-keyword\\">let</span> counter=<span class=\\"hljs-built_in\\">Array</span>(nums.length).fill(<span class=\\"hljs-number\\">0</span>)\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> [<span class=\\"hljs-keyword\\">from</span>,to] <span class=\\"hljs-keyword\\">of</span> requests){\\n        counter[<span class=\\"hljs-keyword\\">from</span>]++\\n        <span class=\\"hljs-keyword\\">if</span>(to+<span class=\\"hljs-number\\">1</span>&lt;nums.length)counter[to+<span class=\\"hljs-number\\">1</span>]--\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> eachCount=<span class=\\"hljs-built_in\\">Array</span>(nums.length).fill().map(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">n,i</span>)=&gt;</span>[i,<span class=\\"hljs-number\\">0</span>])\\n    <span class=\\"hljs-keyword\\">let</span> freq=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;counter.length;i++){\\n        freq+=counter[i]\\n        eachCount[i][<span class=\\"hljs-number\\">1</span>]=freq\\n    }\\n    eachCount.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>b[<span class=\\"hljs-number\\">1</span>]-a[<span class=\\"hljs-number\\">1</span>])\\n    nums.sort(<span class=\\"hljs-function\\">(<span class=\\"hljs-params\\">a,b</span>)=&gt;</span>b-a)\\n    <span class=\\"hljs-keyword\\">let</span> ans=[]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> correctIdx=eachCount[i][<span class=\\"hljs-number\\">0</span>]\\n        ans[correctIdx]=nums[i]\\n    }\\n    <span class=\\"hljs-comment\\">// console.log(ans,eachCount)</span>\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;eachCount.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> idx=eachCount[i][<span class=\\"hljs-number\\">0</span>]\\n        res=(res+eachCount[i][<span class=\\"hljs-number\\">1</span>]*ans[idx]) % MOD\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"maximum-sum-obtained-of-any-permutation","hasThinking":false,"content":"<p>\u6709\u4e00\u4e2a\u6574\u6570\u6570\u7ec4&nbsp;<code>nums</code>&nbsp;\uff0c\u548c\u4e00\u4e2a\u67e5\u8be2\u6570\u7ec4&nbsp;<code>requests</code>&nbsp;\uff0c\u5176\u4e2d&nbsp;<code>requests[i] = [start<sub>i</sub>, end<sub>i</sub>]</code>&nbsp;\u3002\u7b2c&nbsp;<code>i</code>&nbsp;\u4e2a\u67e5\u8be2\u6c42&nbsp;<code>nums[start<sub>i</sub>] + nums[start<sub>i</sub> + 1] + ... + nums[end<sub>i</sub> - 1] + nums[end<sub>i</sub>]</code>&nbsp;\u7684\u7ed3\u679c&nbsp;\uff0c<code>start<sub>i</sub></code> \u548c&nbsp;<code>end<sub>i</sub></code>&nbsp;\u6570\u7ec4\u7d22\u5f15\u90fd\u662f <strong>\u4ece 0 \u5f00\u59cb</strong> \u7684\u3002</p>\\n\\n<p>\u4f60\u53ef\u4ee5\u4efb\u610f\u6392\u5217 <code>nums</code>&nbsp;\u4e2d\u7684\u6570\u5b57\uff0c\u8bf7\u4f60\u8fd4\u56de\u6240\u6709\u67e5\u8be2\u7ed3\u679c\u4e4b\u548c\u7684\u6700\u5927\u503c\u3002</p>\\n\\n<p>\u7531\u4e8e\u7b54\u6848\u53ef\u80fd\u4f1a\u5f88\u5927\uff0c\u8bf7\u4f60\u5c06\u5b83\u5bf9&nbsp;<code>10<sup>9</sup> + 7</code>&nbsp;<strong>\u53d6\u4f59</strong>&nbsp;\u540e\u8fd4\u56de\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>nums = [1,2,3,4,5], requests = [[1,3],[0,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>19\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e00\u4e2a\u53ef\u884c\u7684 nums \u6392\u5217\u4e3a [2,1,3,4,5]\uff0c\u5e76\u6709\u5982\u4e0b\u7ed3\u679c\uff1a\\nrequests[0] -&gt; nums[1] + nums[2] + nums[3] = 1 + 3 + 4 = 8\\nrequests[1] -&gt; nums[0] + nums[1] = 2 + 1 = 3\\n\u603b\u548c\u4e3a\uff1a8 + 3 = 11\u3002\\n\u4e00\u4e2a\u603b\u548c\u66f4\u5927\u7684\u6392\u5217\u4e3a [3,5,4,2,1]\uff0c\u5e76\u6709\u5982\u4e0b\u7ed3\u679c\uff1a\\nrequests[0] -&gt; nums[1] + nums[2] + nums[3] = 5 + 4 + 2 = 11\\nrequests[1] -&gt; nums[0] + nums[1] = 3 + 5  = 8\\n\u603b\u548c\u4e3a\uff1a 11 + 8 = 19\uff0c\u8fd9\u4e2a\u65b9\u6848\u662f\u6240\u6709\u6392\u5217\u4e2d\u67e5\u8be2\u4e4b\u548c\u6700\u5927\u7684\u7ed3\u679c\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>nums = [1,2,3,4,5,6], requests = [[0,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>11\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e00\u4e2a\u603b\u548c\u6700\u5927\u7684\u6392\u5217\u4e3a [6,5,4,3,2,1] \uff0c\u67e5\u8be2\u548c\u4e3a [11]\u3002</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>nums = [1,2,3,4,5,10], requests = [[0,2],[1,3],[1,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>47\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e00\u4e2a\u548c\u6700\u5927\u7684\u6392\u5217\u4e3a [4,10,5,3,2,1] \uff0c\u67e5\u8be2\u7ed3\u679c\u5206\u522b\u4e3a [19,18,10]\u3002</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>n == nums.length</code></li>\\n\\t<li><code>1 &lt;= n &lt;= 10<sup>5</sup></code></li>\\n\\t<li><code>0 &lt;= nums[i]&nbsp;&lt;= 10<sup>5</sup></code></li>\\n\\t<li><code>1 &lt;= requests.length &lt;=&nbsp;10<sup>5</sup></code></li>\\n\\t<li><code>requests[i].length == 2</code></li>\\n\\t<li><code>0 &lt;= start<sub>i</sub>&nbsp;&lt;= end<sub>i</sub>&nbsp;&lt;&nbsp;n</code></li>\\n</ul>\\n","title":"1589. \u6240\u6709\u6392\u5217\u4e2d\u7684\u6700\u5927\u548c","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1589"}')}}]);